SUBCATEGORY_TAXONOMY = {}
_contract_type_map = {
    "SaaS": "License Agreement",
    "Managed Service": "Service Agreement",
    "Managed Service + Platform": "Service Agreement",
    "Data Subscription": "License Agreement",
    "Data Subscription + SaaS": "License Agreement",
    "Service Agreement + SaaS": "Service Agreement",
    "Banking Agreement": "Service Agreement",
    "Card Program Agreement": "Service Agreement",
    "Logistics Services Agreement": "Service Agreement",
    "Transportation Agreement": "Service Agreement",
    "Manufacturing Agreement": "Service Agreement",
    "Print Agreement": "Service Agreement",
    "Agency Agreement": "Service Agreement",
    "Retainer Agreement": "Service Agreement",
    "AIA Contract / EPC": "Service Agreement",
    "TPA Agreement": "Service Agreement",
    "Supply Agreement": "Supply Agreement",
    "Professional Services Agreement": "Professional Services",
    "Master Service Agreement": "Master Services Agreement",
}
for category_key, category_data in CATEGORY_TAXONOMY.items():
    for sub in category_data.get("subcategories", []):
        raw_contract_type = sub.get("contract_type", "Service Agreement")
        normalized_contract_type = _contract_type_map.get(raw_contract_type, raw_contract_type)
        valid_contract_types = {
            "Service Agreement", "License Agreement", "Supply Agreement",
            "Professional Services", "Master Services Agreement", "SOW"
        }
        if normalized_contract_type not in valid_contract_types:
            normalized_contract_type = "Service Agreement"
        SUBCATEGORY_TAXONOMY[sub["name"]] = {
            **sub,
            "category": category_data["label"],
            "description": sub.get("notes", ""),
            "contract_type": normalized_contract_type,
        }
